const outputItems = [];

$input.all().forEach((inputItem) => {
  const { json, binary } = inputItem;

  // Iterate all binary attachments (attachment_0, attachment_1...)
  const binaryKeys = Object.keys(binary || {});

  if (binaryKeys.length === 0) {
    // Return empty metadata when no attachments to avoid process interruption
    outputItems.push({
      json: {
        "attachment_name": "",
        "attachment_extension": "",
        "mime_type": "",
        "attachment_size_bytes": 0,
        "attachment_size_mb": 0,
        "has_attachment": false,
        "email_id": json.id || ""
      },
      binary: {}
    });
    return;
  }

  // Process each attachment when available
  binaryKeys.forEach((binaryKey) => {
    const att = binary[binaryKey];
    if (!att) return;

    // Extract metadata from binary
    const fileName = att.fileName || "";
    const fileExt = att.fileExtension || "";
    const mimeType = att.mimeType || "";
    const fileSizeStr = att.fileSize || "0 kB";

    // Parse file size to bytes
    let fileSizeBytes = 0;
    const sizeMatch = fileSizeStr.match(/(\d+(?:\.\d+)?)\s*(kB|MB|GB|B)/i);
    if (sizeMatch) {
      const value = parseFloat(sizeMatch[1]);
      const unit = sizeMatch[2].toUpperCase();
      switch (unit) {
        case "B":
          fileSizeBytes = value;
          break;
        case "KB":
          fileSizeBytes = value * 1024;
          break;
        case "MB":
          fileSizeBytes = value * 1024 * 1024;
          break;
        case "GB":
          fileSizeBytes = value * 1024 * 1024 * 1024;
          break;
      }
    }

    const fileSizeMB = (fileSizeBytes / 1024 / 1024).toFixed(2);

    outputItems.push({
      json: {
        "attachment_name": fileName,
        "attachment_extension": fileExt,
        "mime_type": mimeType,
        "attachment_size_bytes": Math.round(fileSizeBytes),
        "attachment_size_mb": parseFloat(fileSizeMB),
        "has_attachment": true,
        "email_id": json.id || "",
        "binary_key": binaryKey // Used to associate binary files later
      },
      // Core modification: Rename all attachments to "file" instead of attachment_X
      binary: {
        file: att
      }
    });
  });
});

return outputItems;

var data = $node['Laiye ADP HTTP Request'].json.data.extraction_result;                                                                                            var mainFields = {};
var detailHeaders = [];                                                                                                                                
var detailRows = [];

for (var i = 0; i < data.length; i++) {
  if (data[i].table_values == null) {
    var name = data[i].field_name;
    var val = 'No Result';
    if (data[i].field_values && data[i].field_values[0]) {
      val = data[i].field_values[0].field_value || 'No Result';
    }
    mainFields[name] = val;
  } else {
    for (var j = 0; j < data[i].table_values[0].length; j++) {
      detailHeaders.push(data[i].table_values[0][j].field_name);
    }
    for (var k = 0; k < data[i].table_values.length; k++) {
      var row = [];
      for (var m = 0; m < data[i].table_values[k].length; m++) {
        var cell = 'No Result';
        if (data[i].table_values[k][m].field_values && data[i].table_values[k][m].field_values[0]) {
          cell = data[i].table_values[k][m].field_values[0].field_value || 'No Result';
        }
        row.push(cell);
      }
      detailRows.push(row);
    }
  }
}

var keys = Object.keys(mainFields);
var vals = Object.values(mainFields);

var xml = '';
xml = xml + '<?xml version="1.0"?>';
xml = xml + '<Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet">';
xml = xml + '<Worksheet ss:Name="Fields"><Table>';
xml = xml + '<Row>';
for (var n = 0; n < keys.length; n++) {
  xml = xml + '<Cell><Data ss:Type="String">' + keys[n] + '</Data></Cell>';
}
xml = xml + '</Row>';
xml = xml + '<Row>';
for (var p = 0; p < vals.length; p++) {
  xml = xml + '<Cell><Data ss:Type="String">' + vals[p] + '</Data></Cell>';
}
xml = xml + '</Row>';
xml = xml + '</Table></Worksheet>';

if (detailHeaders.length > 0) {
  xml = xml + '<Worksheet ss:Name="Product Details Table"><Table>';
  xml = xml + '<Row>';
  for (var q = 0; q < detailHeaders.length; q++) {
    xml = xml + '<Cell><Data ss:Type="String">' + detailHeaders[q] + '</Data></Cell>';
  }
  xml = xml + '</Row>';
  for (var r = 0; r < detailRows.length; r++) {
    xml = xml + '<Row>';
    for (var s = 0; s < detailRows[r].length; s++) {
      xml = xml + '<Cell><Data ss:Type="String">' + detailRows[r][s] + '</Data></Cell>';
    }
    xml = xml + '</Row>';
  }
  xml = xml + '</Table></Worksheet>';
}

xml = xml + '</Workbook>';

return [{
  binary: {
    data: {
      data: Buffer.from(xml, 'utf-8').toString('base64'),
      mimeType: 'application/vnd.ms-excel',
      fileName: 'data.xls'
    }
  }
}];
